logic.script:
const validators = cluster.getAgentsByRole('validator');
const validatorIds = new Set(validators.map(v => v.id));
const lastPush = ledger.findLast({ topic: 'IMPLEMENTATION_READY' });
if (!lastPush) return false;
const responses = ledger.query({ topic: 'VALIDATION_RESULT', since: lastPush.timestamp });
const latestByValidator = new Map();
for (const r of responses) {
  if (!validatorIds.has(r.sender)) continue;
  latestByValidator.set(r.sender, r);
}
if (latestByValidator.size < validators.length) return false;
return [...latestByValidator.values()].some(r => {
  const approved = r.content?.data?.approved;
  return approved === false || approved === 'false';
});

const lastPush = ledger.findLast({ topic: 'IMPLEMENTATION_READY' });
if (!lastPush) return false;
const existingSynthesis = ledger.findLast({ topic: 'SYNTHESIS_COMPLETE' });
if (existingSynthesis) return false;
const validators = cluster.getAgentsByRole('validator');
const validatorIds = new Set(validators.map(v => v.id));
const results = ledger.query({ topic: 'VALIDATION_RESULT', since: lastPush.timestamp });
const latestByValidator = new Map();
for (const r of results) {
  if (!validatorIds.has(r.sender)) continue;
  latestByValidator.set(r.sender, r);
}
if (latestByValidator.size < validators.length) return false;
const allApproved = [...latestByValidator.values()].every(r => {
  const approved = r.content?.data?.approved;
  return approved === true || approved === 'true';
});
if (allApproved) return true;
const implCount = ledger.count({ topic: 'IMPLEMENTATION_READY', sender: 'analyst' });
return implCount >= {{max_iterations}};
